import React from "react";
import Image from "next/image";

type THoverablePhoto = {
  photoSrc: string;
  onHover: boolean;
  setOnHover: React.Dispatch<React.SetStateAction<boolean>>;
};

const HoverablePhoto = ({ onHover, setOnHover, photoSrc }: THoverablePhoto) => {
  return (
    <div
      className="border-2 border-solid w-fit h-fit border-red-500 bg-yellow-400 rounded-full relative"
      onMouseEnter={() => setOnHover(true)}
      onMouseLeave={() => setOnHover(false)}
    >
      {onHover && (
        <div className="w-[180px] h-[180px] bg-black/50 rounded-full absolute">
          <button className="w-full h-full text-white">Change Photo</button>
        </div>
      )}
      <Image
        src={photoSrc}
        alt="Profile picture"
        width={180}
        height={180}
        priority
      />
    </div>
  );
};

export default HoverablePhoto;
